import urllib.request
import json
import os
import sys

api_key = os.environ.get('HOOKDECK_API_KEY')
run_id = os.environ.get('ZEALT_RUN_ID')

base_url = "https://api.hookdeck.com/2025-07-01"

def api_request(method, path):
    url = f"{base_url}{path}"
    headers = {
        "Authorization": f"Bearer {api_key}",
        "Accept": "application/json",
        "User-Agent": "curl/8.7.1"
    }
    req = urllib.request.Request(url, headers=headers, method=method)
    try:
        with urllib.request.urlopen(req) as response:
            return json.loads(response.read().decode('utf-8'))
    except Exception as e:
        print(f"Error {method} {path}: {e}")
        return None

# Find destination
destinations = api_request("GET", "/destinations")
dest_id = None
if destinations and "models" in destinations:
    for dest in destinations["models"]:
        if run_id in dest.get("name", ""):
            dest_id = dest["id"]
            print(f"Found destination: {dest_id} ({dest['name']})")

if dest_id:
    events = api_request("GET", f"/events?destination_id={dest_id}")
    if events and "models" in events:
        for ev in events["models"]:
            print(f"Event ID: {ev['id']}, Status: {ev['status']}, Successful At: {ev.get('successful_at')}")
    else:
        print("No events found")
else:
    print("No destination found")
